// // This is a 1-to-2 demultiplexer that outputs one of two 4-bit inputs based on a 1-bit select signal.
module mux2to1(input [3:0] a,  
               input [3:0] b,  
               input sel,  
               output reg [3:0] y);  
    always @(*) begin  
        if (sel)  
            y = b;  
        else  
            y = a;  
    end  
endmodule
